def seed(db_path: str = str(DB_PATH)) -> None:
    conn = sqlite3.connect(db_path)
    cur = conn.cursor()

    for sql in [
        "DROP TABLE IF EXISTS messier;",
        "DROP TABLE IF EXISTS caldwell;",
        "DROP TABLE IF EXISTS ngc_flags;",
    ] + [
        "CREATE TABLE IF NOT EXISTS messier (id INTEGER PRIMARY KEY, catalog_id TEXT UNIQUE NOT NULL, name TEXT, type TEXT, ra_hours REAL, dec_deg REAL, constellation TEXT, magnitude REAL, surface_brightness REAL, size_arcmin REAL, description TEXT);",
        "CREATE TABLE IF NOT EXISTS caldwell (id INTEGER PRIMARY KEY, catalog_id TEXT UNIQUE NOT NULL, name TEXT, common_name TEXT, type TEXT, ra_hours REAL, dec_deg REAL, constellation TEXT, magnitude REAL, description TEXT);",
        "CREATE TABLE IF NOT EXISTS ngc_flags (id INTEGER PRIMARY KEY, catalog_id TEXT UNIQUE NOT NULL, name TEXT, type TEXT, ra_hours REAL, dec_deg REAL, constellation TEXT, magnitude REAL, size_arcmin REAL, description TEXT);",
    ]:
        cur.execute(sql)

    for row in MESSIER_DATA:
        cur.execute(
            "INSERT OR IGNORE INTO messier (catalog_id, name, type, ra_hours, dec_deg, constellation, magnitude, surface_brightness, size_arcmin, description) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
            row,
        )

    for row in CALDWELL_DATA:
        cur.execute(
            "INSERT OR IGNORE INTO caldwell (catalog_id, name, common_name, type, ra_hours, dec_deg, constellation, magnitude, description) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)",
            row,
        )

    for row in NGC_FLAGS_DATA:
        cur.execute(
            "INSERT OR IGNORE INTO ngc_flags (catalog_id, name, type, ra_hours, dec_deg, constellation, magnitude, size_arcmin, description) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)",
            row,
        )

    conn.commit()
    cur.execute("SELECT COUNT(*) FROM messier")
    m_count = cur.fetchone()[0]
    cur.execute("SELECT COUNT(*) FROM caldwell")
    c_count = cur.fetchone()[0]
    cur.execute("SELECT COUNT(*) FROM ngc_flags")
    n_count = cur.fetchone()[0]
    print(f"Seeded: {m_count} Messier, {c_count} Caldwell, {n_count} NGC flagship objects.")
    conn.close()


if __name__ == "__main__":
    seed()
